import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.stream.JsonReader;
import com.google.gson.stream.JsonToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.InOrder;

import java.io.IOException;
import java.lang.reflect.Method;
import java.util.Date;

class DefaultDateTypeAdapterTest {

    private DefaultDateTypeAdapter<Date> adapter;
    private DefaultDateTypeAdapter.DateType<Date> dateType;

    @BeforeEach
    void setUp() {
        dateType = mock(DefaultDateTypeAdapter.DateType.class);
        adapter = new DefaultDateTypeAdapter<Date>(dateType, "yyyy-MM-dd") {
            @Override
            protected Date deserializeToDate(JsonReader in) throws IOException {
                // This method is private in actual class, so we override here for testing
                return super.deserializeToDate(in);
            }
        };
    }

    @Test
    void read_shouldReturnNull_whenJsonTokenIsNull() throws IOException {
        JsonReader in = mock(JsonReader.class);
        when(in.peek()).thenReturn(JsonToken.NULL);

        Date result = adapter.read(in);

        InOrder inOrder = inOrder(in);
        inOrder.verify(in).peek();
        inOrder.verify(in).nextNull();
        assertNull(result);
    }

    @Test
    void read_shouldReturnDeserializedDate_whenJsonTokenIsNotNull() throws Exception {
        JsonReader in = mock(JsonReader.class);
        when(in.peek()).thenReturn(JsonToken.STRING);

        Date expectedDate = new Date();
        when(dateType.deserialize(any(Date.class))).thenReturn(expectedDate);

        // Use reflection to invoke private deserializeToDate method
        Method deserializeToDateMethod = DefaultDateTypeAdapter.class.getDeclaredMethod("deserializeToDate", JsonReader.class);
        deserializeToDateMethod.setAccessible(true);

        // Mock deserializeToDate to return a specific Date
        DefaultDateTypeAdapter<Date> spyAdapter = spy(adapter);
        doReturn(expectedDate).when(spyAdapter).deserializeToDate(in);

        Date result = spyAdapter.read(in);

        InOrder inOrder = inOrder(in, spyAdapter);
        inOrder.verify(in).peek();
        inOrder.verify(spyAdapter).deserializeToDate(in);
        inOrder.verify(dateType).deserialize(expectedDate);

        assertEquals(expectedDate, result);
    }
}
